mapper.select:
/* clsAcntCloseMgmtMapper.getClsAcntCloseStat */
SELECT
    CLOSE_STAT_CD
FROM
    CLS_ACNT_CLOSE_INFO A
WHERE
    CLS_ACNT_YM = #{CLS_ACNT_YM, jdbcType=VARCHAR}
    AND CLS_ACNT_DUTY_CD = #{CLS_ACNT_DUTY_CD, jdbcType=VARCHAR}
    AND SRL_NUM = #{SRL_NUM, jdbcType=NUMERIC}

mapper.insert:
/* clsAcntCloseMgmtMapper.insertClsAcntDltList */ INSERT INTO CLS_ACNT_DTL ( CLS_ACNT_YM , ORGN_ID , SALE_ITM_CD , CLS_ACNT_STDR_CD , CLS_ACNT_ITM_CD , CLS_ACNT_TRGT_AMT , CLS_ACNT_PROC_AMT , DPST_PROC_AMT , REGST_ID , REG_DTTM , RVISN_ID , RVISN_DTTM ) SELECT #{CLS_ACNT_YM, jdbcType=VARCHAR} , A.ORGN_ID , A.SALE_ITM_CD , A.CLS_ACNT_STDR_CD , B.CLS_ACNT_ITM_CD , SUM(NVL(A.SALE_AMT, 0) + NVL(A.VAT, 0)) AS CLS_ACNT_TRGT_AMT , SUM(NVL(C.CLS_ACNT_PROC_AMT, 0)) AS CLS_ACNT_PROC_AMT , SUM(NVL(A.DPST_PROC_AMT, 0) - NVL(C.CLS_ACNT_PROC_AMT, 0)) AS DPST_PROC_AMT , #{USER_ID, jdbcType=VARCHAR} , SYSDATE , #{USER_ID, jdbcType=VARCHAR} , SYSDATE FROM CLS_SALE_INFO A , CLS_SALE_ITM_INFO B , ( /* 가결산 입금상계금액/(-)매출 상계 */ SELECT A.STOF_SALE_DT AS SALE_DT , A.ORGN_ID AS ORGN_ID , A.STOF_SALE_ITM_CD AS SALE_ITM_CD , A.STOF_SALE_SRL_NUM AS SALE_SRL_NUM , SUM(NVL(A.STOF_AMT, 0)) AS CLS_ACNT_PROC_AMT FROM CLS_STOF_INFO A WHERE A.STOF_SALE_DT LIKE #{CLS_ACNT_YM, jdbcType=VARCHAR} || '%' AND A.STOF_OCCR_SCTN_CD IN ('44') GROUP BY A.STOF_SALE_DT , A.ORGN_ID , A.STOF_SALE_ITM_CD , A.STOF_SALE_SRL_NUM
HAVING SUM(A.STOF_AMT) <> 0
) C WHERE A.CLS_ACNT_YM = #{CLS_ACNT_YM, jdbcType=VARCHAR} AND A.SALE_STAT_CD = '30' AND A.SALE_ITM_CD = B.SALE_ITM_CD AND B.CLS_ACNT_PROC_YN = 'Y' /* 결산처리여부 */ AND A.SALE_DT = C.SALE_DT(+) AND A.ORGN_ID = C.ORGN_ID(+) AND A.SALE_ITM_CD = C.SALE_ITM_CD(+) AND A.SALE_SRL_NUM = C.SALE_SRL_NUM(+) GROUP BY A.ORGN_ID , A.SALE_ITM_CD , A.CLS_ACNT_STDR_CD , B.CLS_ACNT_ITM_CD
